import os
import re

def _parse_size_string(size_string):
    if isinstance(size_string, (int, float)):
        return int(size_string)

    size_string = size_string.strip()
    match = re.match(r'^(\d+(\.\d+)?)\s*([KMGT]?B)?$', size_string, re.IGNORECASE)
    if not match:
        raise ValueError(f"Invalid size string format: {size_string}")

    value = float(match.group(1))
    unit = (match.group(3) or 'B').upper()

    units = {
        'B': 1,
        'KB': 1024,
        'MB': 1024**2,
        'GB': 1024**3,
        'TB': 1024**4,
    }

    if unit not in units:
        raise ValueError(f"Unknown unit: {unit}")

    return int(value * units[unit])

def validate_file_size(file_path, size_limit):
    try:
        actual_size = os.path.getsize(file_path)
    except FileNotFoundError:
        return False
    except Exception:
        return False

    try:
        if isinstance(size_limit, str):
            limit_bytes = _parse_size_string(size_limit)
        elif isinstance(size_limit, (int, float)):
            limit_bytes = int(size_limit)
        else:
            return False
    except ValueError:
        return False

    return actual_size <= limit_bytes
